    text += "Functions in this group:\n"
    for node in cluster:
        text += f"- {node}\n"

    text += "\nContext:\n"
    for ctx in contexts:
        if ctx["node"] in cluster:
            text += f"\nNode: {ctx['node']}\n"
            text += f"Upstream: {ctx['upstream']}\n"
            text += f"Downstream: {ctx['downstream']}\n"

    text += "\nCode Snippets:\n"
    for node in cluster:
